package demo.reservation.service;

import demo.reservation.external.UserHttpClient;
import demo.reservation.model.RoomRequestDto;
import demo.reservation.model.RoomResponseDto;
import demo.reservation.model.entity.RoomEntity;
import demo.reservation.repository.RoomRepository;
import jakarta.persistence.EntityNotFoundException;
import lombok.RequiredArgsConstructor;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.HttpStatus;
import org.springframework.stereotype.Service;
import org.springframework.web.server.ResponseStatusException;

import java.util.List;

@Service
@RequiredArgsConstructor
public class RoomService {

    private static final Logger log = LoggerFactory.getLogger(RoomService.class);

    private final RoomRepository roomRepository;
    private final UserHttpClient userHttpClient;

    public RoomResponseDto createRoom(RoomRequestDto roomRequest, String authorizationHeader) {
        ensureAdminAccess(authorizationHeader);

        RoomEntity roomEntity = new RoomEntity();
        roomEntity.setPrice(roomRequest.price());
        roomEntity.setImageUrls(roomRequest.imageUrls());

        RoomEntity saved = roomRepository.save(roomEntity);
        log.info("Room created with id: {}", saved.getId());
        return new RoomResponseDto(saved.getId(), saved.getPrice(), saved.getImageUrls());
    }

    public void deleteRoom(Long id, String authorizationHeader) {
        ensureAdminAccess(authorizationHeader);

        if (!roomRepository.existsById(id)) {
            throw new EntityNotFoundException("Room not found with id: " + id);
        }

        roomRepository.deleteById(id);
        log.info("Room deleted with id: {}", id);
    }

    public List<RoomResponseDto> getAllRooms() {
        List<RoomEntity> rooms = roomRepository.findAll();
        return rooms.stream()
                .map(room -> new RoomResponseDto(room.getId(), room.getPrice(), room.getImageUrls()))
                .toList();
    }

    private void ensureAdminAccess(String authorizationHeader) {
        if (!authorizationHeader.startsWith("Bearer ")) {
            throw new ResponseStatusException(HttpStatus.UNAUTHORIZED, "Authorization header must use Bearer token");
        }

        try {
            var currentUser = userHttpClient.getCurrentUser(authorizationHeader);
            if (currentUser == null || !"ADMIN".equals(currentUser.role())) {
                throw new ResponseStatusException(HttpStatus.FORBIDDEN, "Access denied. Admin role required.");
            }
        } catch (Exception ex) {
            throw new ResponseStatusException(HttpStatus.UNAUTHORIZED, "Invalid token or access denied");
        }
    }
}

package demo.reservation.config;

import lombok.RequiredArgsConstructor;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.authentication.AuthenticationProvider;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.annotation.web.configurers.AbstractHttpConfigurer;
import org.springframework.security.config.http.SessionCreationPolicy;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;

@Configuration
@EnableWebSecurity
@RequiredArgsConstructor
public class SecurityConfig {

    private final JwtAuthenticationFilter jwtAuthFilter;
    private final AuthenticationProvider authenticationProvider;

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
                .csrf(AbstractHttpConfigurer::disable)
                .authorizeHttpRequests(auth -> auth
                        .requestMatchers("/api/v1/auth/**").permitAll()
                        .requestMatchers("/api/v1/users/*/exists").permitAll()
                        .anyRequest().authenticated()
                )
                .sessionManagement(session -> session
                        .sessionCreationPolicy(SessionCreationPolicy.STATELESS)
                )
                .authenticationProvider(authenticationProvider)
                .addFilterBefore(jwtAuthFilter, UsernamePasswordAuthenticationFilter.class);

        return http.build();
    }
}

package demo.reservation.config;

import lombok.RequiredArgsConstructor;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.authentication.AuthenticationProvider;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.annotation.web.configurers.AbstractHttpConfigurer;
import org.springframework.security.config.http.SessionCreationPolicy;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;

@Configuration
@EnableWebSecurity
@RequiredArgsConstructor
public class SecurityConfig {

    private final JwtAuthenticationFilter jwtAuthFilter;
    private final AuthenticationProvider authenticationProvider;

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
                .csrf(AbstractHttpConfigurer::disable)
                .authorizeHttpRequests(auth -> auth
                        .requestMatchers("/api/v1/auth/**").permitAll()
                        .requestMatchers("/api/v1/auth/generate-temp-passwords/**").permitAll()
                        .requestMatchers("/api/v1/auth/reset-password-with-temp").permitAll()
                        .requestMatchers("/api/v1/users/*/exists").permitAll()
                        .anyRequest().authenticated()
                )
                .sessionManagement(session -> session
                        .sessionCreationPolicy(SessionCreationPolicy.STATELESS)
                )
                .authenticationProvider(authenticationProvider)
                .addFilterBefore(jwtAuthFilter, UsernamePasswordAuthenticationFilter.class);

        return http.build();
    }
}

package demo.reservation.controller;

import demo.reservation.model.UserResponseDto;
import demo.reservation.service.UserService;
import lombok.RequiredArgsConstructor;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

@RestController
@RequestMapping("/api/v1/users")
@RequiredArgsConstructor
public class UserController {

    private final UserService userService;

    @GetMapping("/me")
    public ResponseEntity<UserResponseDto> getMyProfile() {
        return ResponseEntity.ok(userService.getCurrentUser());
    }

    @GetMapping("/{id}/exists")
    public ResponseEntity<Void> checkUserExists(@PathVariable Long id) {
        return userService.existsById(id)
                ? ResponseEntity.ok().build()
                : ResponseEntity.status(HttpStatus.NOT_FOUND).build();
    }
}

package demo.reservation.controller;

import demo.reservation.model.AuthenticationResponse;
import demo.reservation.model.UserResponseDto;
import demo.reservation.service.UserService;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/v1/users")
@RequiredArgsConstructor
@Slf4j
public class UserController {

    private final UserService userService;

    @GetMapping("/me")
    public ResponseEntity<UserResponseDto> getMyProfile() {
        log.info("Getting current user profile");
        UserResponseDto user = userService.getCurrentUser();
        log.info("Current user: id={}, email={}, role={}", user.id(), user.email(), user.role());
        return ResponseEntity.ok(user);
    }

    @GetMapping("/{id}/exists")
    public ResponseEntity<Void> checkUserExists(@PathVariable Long id) {
        return userService.existsById(id)
                ? ResponseEntity.ok().build()
                : ResponseEntity.status(HttpStatus.NOT_FOUND).build();
    }

    @PostMapping("/promote-to-admin")
    public ResponseEntity<AuthenticationResponse> promoteToAdmin(
            @RequestParam(name = "secret") String secretKey
    ) {
        log.info("Promoting current user to admin with secret key and returning new token");
        AuthenticationResponse response = userService.promoteToAdminWithSecretAndRefreshToken(secretKey);
        log.info("User promoted to admin and new token generated");
        return ResponseEntity.ok(response);
    }

    @PostMapping("/promote-to-admin-with-token")
    public ResponseEntity<AuthenticationResponse> promoteToAdminWithToken(
            @RequestParam(name = "secret") String secretKey
    ) {
        log.info("Promoting current user to admin with secret key and returning new token");
        AuthenticationResponse response = userService.promoteToAdminWithSecretAndRefreshToken(secretKey);
        log.info("User promoted to admin and new token generated");
        return ResponseEntity.ok(response);
    }

    @PostMapping("/users/{userId}/promote-to-admin")
    public ResponseEntity<UserResponseDto> promoteUserToAdmin(
            @PathVariable Long userId,
            @RequestHeader("Authorization") String authorizationHeader
    ) {
        log.info("Admin attempting to promote user {} to admin", userId);
        UserResponseDto updatedUser = userService.promoteUserToAdmin(userId);
        log.info("User {} promoted to admin by admin", userId);
        return ResponseEntity.ok(updatedUser);
    }

    @PostMapping("/refresh-token")
    public ResponseEntity<AuthenticationResponse> refreshToken() {
        log.info("Refreshing token for current user");
        String email = org.springframework.security.core.context.SecurityContextHolder
                .getContext()
                .getAuthentication()
                .getName();
        AuthenticationResponse response = userService.refreshToken(email);
        log.info("Token refreshed for user: {}", email);
        return ResponseEntity.ok(response);
    }
}

