package demo.reservation.service;

import demo.reservation.model.entity.TemporaryPassword;
import demo.reservation.model.entity.UserEntity;
import demo.reservation.repository.TemporaryPasswordRepository;
import lombok.RequiredArgsConstructor;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;

@Service
@RequiredArgsConstructor
@Transactional
public class TemporaryPasswordService {

    private final TemporaryPasswordRepository repository;
    private final PasswordEncoder passwordEncoder;

    private static final int TEMP_PASSWORD_COUNT = 10;
    private static final int TEMP_PASSWORD_VALIDITY_HOURS = 24;

    /**
     * Генерирует 10 новых временных паролей для пользователя
     * Удаляет старые неиспользованные пароли
     * @param user пользователь
     * @return список сгенерированных временных паролей в открытом виде (только один раз)
     */
    public List<String> generateTemporaryPasswords(UserEntity user) {
        // Удаляем все старые неиспользованные пароли
        repository.deleteAllByUser(user);

        List<String> generatedPasswords = new ArrayList<>();
        LocalDateTime now = LocalDateTime.now();
        LocalDateTime expiresAt = now.plusHours(TEMP_PASSWORD_VALIDITY_HOURS);

        // Генерируем 10 временных паролей
        for (int i = 0; i < TEMP_PASSWORD_COUNT; i++) {
            String tempPassword = UUID.randomUUID().toString().replace("-", "");
            generatedPasswords.add(tempPassword);

            TemporaryPassword temp = TemporaryPassword.builder()
                    .user(user)
                    .hashedPassword(passwordEncoder.encode(tempPassword))
                    .isUsed(false)
                    .createdAt(now)
                    .expiresAt(expiresAt)
                    .build();

            repository.save(temp);
        }

        return generatedPasswords;
    }

    /**
     * Проверяет и использует временный пароль
     * @param user пользователь
     * @param tempPassword временный пароль
     * @return true если проверка успешна и пароль отмечен как использованный
     */
    public boolean validateAndUseTemporaryPassword(UserEntity user, String tempPassword) {
        List<TemporaryPassword> unusedPasswords = repository.findAllByUserAndIsUsedFalse(user);

        for (TemporaryPassword tp : unusedPasswords) {
            // Проверяем, что пароль не истек
            if (LocalDateTime.now().isAfter(tp.getExpiresAt())) {
                continue;
            }

            // Проверяем совпадение пароля
            if (passwordEncoder.matches(tempPassword, tp.getHashedPassword())) {
                tp.setIsUsed(true);
                repository.save(tp);
                return true;
            }
        }

        return false;
    }

    /**
     * Получает количество оставшихся неиспользованных временных паролей
     * @param user пользователь
     * @return количество неиспользованных паролей
     */
    @Transactional(readOnly = true)
    public long getUnusedPasswordsCount(UserEntity user) {
        return repository.countByUserAndIsUsedFalse(user);
    }

    /**
     * Получает список информации о неиспользованных временных паролях (без самих паролей)
     * @param user пользователь
     * @return список временных паролей
     */
    @Transactional(readOnly = true)
    public List<TemporaryPassword> getUnusedPasswords(UserEntity user) {
        return repository.findAllByUserAndIsUsedFalse(user);
    }
}

package demo.reservation.service;

import demo.reservation.mapper.UserEntityMapper;
import demo.reservation.model.UserResponseDto;
import demo.reservation.model.entity.UserEntity;
import demo.reservation.repository.UserRepository;
import lombok.RequiredArgsConstructor;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.security.core.userdetails.UsernameNotFoundException;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
import org.springframework.web.server.ResponseStatusException;

@Service
@RequiredArgsConstructor
@Transactional(readOnly = true)
public class UserService {

    private final UserRepository repository;

    @Value("${app.admin-secret-key}")
    private String adminSecretKey;


    public UserResponseDto getCurrentUser() {
        String email = SecurityContextHolder.getContext().getAuthentication().getName();

        return mapper.toUserResponseDto(user);
    }


    public UserEntity findByEmail(String email) {
        return repository.findByEmail(email)
                .orElseThrow(() -> new UsernameNotFoundException("User not found"));
    }

    public boolean existsById(Long id) {
        return repository.existsById(id);
    }

    @Transactional
    public void deleteUser(Long id) {
        repository.deleteById(id);
    }

    @Transactional
    public UserResponseDto promoteToAdminWithSecret(String secretKey) {
        if (!secretKey.equals(adminSecretKey)) {
            throw new ResponseStatusException(HttpStatus.UNAUTHORIZED, "Invalid admin secret key");
        }

        String email = SecurityContextHolder.getContext().getAuthentication().getName();
        UserEntity user = repository.findByEmail(email)
                .orElseThrow(() -> new UsernameNotFoundException("Пользователь не найден"));

        if (user.getRole() == UserRole.ADMIN) {
            throw new ResponseStatusException(HttpStatus.BAD_REQUEST, "User is already an admin");
        }

        user.setRole(UserRole.ADMIN);
        repository.save(user);
        return mapper.toUserResponseDto(user);
    }

    @Transactional
    public UserResponseDto promoteUserToAdmin(Long userId) {
        String email = SecurityContextHolder.getContext().getAuthentication().getName();
        UserEntity currentUser = repository.findByEmail(email)
                .orElseThrow(() -> new UsernameNotFoundException("Пользователь не найден"));

        if (currentUser.getRole() != UserRole.ADMIN) {
            throw new ResponseStatusException(HttpStatus.FORBIDDEN, "Only admins can promote users to admin");
        }

        UserEntity userToPromote = repository.findById(userId)
                .orElseThrow(() -> new EntityNotFoundException("User not found with id: " + userId));

        if (userToPromote.getRole() == UserRole.ADMIN) {
            throw new ResponseStatusException(HttpStatus.BAD_REQUEST, "User is already an admin");
        }

        userToPromote.setRole(UserRole.ADMIN);
        repository.save(userToPromote);
        return mapper.toUserResponseDto(userToPromote);
    }
}

package demo.reservation.service;

import demo.reservation.mapper.UserEntityMapper;
import demo.reservation.model.AuthenticationResponse;
import demo.reservation.model.UserResponseDto;
import demo.reservation.model.UserRole;
import demo.reservation.model.entity.UserEntity;
import demo.reservation.repository.UserRepository;
import jakarta.persistence.EntityNotFoundException;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.http.HttpStatus;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.security.core.userdetails.UsernameNotFoundException;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
import org.springframework.web.server.ResponseStatusException;

@Service
@RequiredArgsConstructor
@Transactional(readOnly = true)
@Slf4j
public class UserService {

    private final UserRepository repository;
    private final UserEntityMapper mapper;
    private final AuthenticationService authenticationService;

    @Value("${app.admin-secret-key}")
    private String adminSecretKey;


    public UserResponseDto getCurrentUser() {
        String email = SecurityContextHolder.getContext().getAuthentication().getName();
        UserEntity user = repository.findByEmail(email)
                .orElseThrow(() -> new UsernameNotFoundException("Пользователь не найден"));

        return mapper.toUserResponseDto(user);
    }


    public UserEntity findByEmail(String email) {
        return repository.findByEmail(email)
                .orElseThrow(() -> new UsernameNotFoundException("User not found"));
    }

    public boolean existsById(Long id) {
        return repository.existsById(id);
    }

    @Transactional
    public void deleteUser(Long id) {
        repository.deleteById(id);
    }

    @Transactional
    public UserResponseDto promoteToAdminWithSecret(String secretKey) {
        log.info("Attempting to promote user to admin with secret key");

        if (!secretKey.equals(adminSecretKey)) {
            log.warn("Invalid admin secret key provided");
            throw new ResponseStatusException(HttpStatus.UNAUTHORIZED, "Invalid admin secret key");
        }

        String email = SecurityContextHolder.getContext().getAuthentication().getName();
        log.info("Promoting user with email: {}", email);

        UserEntity user = repository.findByEmail(email)
                .orElseThrow(() -> new UsernameNotFoundException("Пользователь не найден"));

        if (user.getRole() == UserRole.ADMIN) {
            log.warn("User {} is already an admin", email);
            throw new ResponseStatusException(HttpStatus.BAD_REQUEST, "User is already an admin");
        }

        user.setRole(UserRole.ADMIN);
        repository.save(user);
        log.info("Successfully promoted user {} to ADMIN", email);

        return mapper.toUserResponseDto(user);
    }

    @Transactional
    public UserResponseDto promoteUserToAdmin(Long userId) {
        String currentEmail = SecurityContextHolder.getContext().getAuthentication().getName();
        log.info("User {} attempting to promote user {} to admin", currentEmail, userId);

        UserEntity currentUser = repository.findByEmail(currentEmail)
                .orElseThrow(() -> new UsernameNotFoundException("Пользователь не найден"));

        log.info("Current user role: {}", currentUser.getRole());

        if (currentUser.getRole() != UserRole.ADMIN) {
            log.warn("User {} with role {} tried to promote another user", currentEmail, currentUser.getRole());
            throw new ResponseStatusException(HttpStatus.FORBIDDEN, "Only admins can promote users to admin");
        }

        UserEntity userToPromote = repository.findById(userId)
                .orElseThrow(() -> new EntityNotFoundException("User not found with id: " + userId));

        if (userToPromote.getRole() == UserRole.ADMIN) {
            log.warn("User {} is already an admin", userId);
            throw new ResponseStatusException(HttpStatus.BAD_REQUEST, "User is already an admin");
        }

        userToPromote.setRole(UserRole.ADMIN);
        repository.save(userToPromote);
        log.info("Successfully promoted user {} to ADMIN by {}", userId, currentEmail);

        return mapper.toUserResponseDto(userToPromote);
    }

    @Transactional
    public AuthenticationResponse promoteToAdminWithSecretAndRefreshToken(String secretKey) {
        log.info("Starting promotion to admin with token refresh");
        UserResponseDto userResponse = promoteToAdminWithSecret(secretKey);
        log.info("User promoted, role in response: {}", userResponse.role());

        String email = SecurityContextHolder.getContext().getAuthentication().getName();
        log.info("Getting fresh token for email: {}", email);

        AuthenticationResponse tokenResponse = authenticationService.refreshToken(email);
        log.info("New token generated, checking if it contains admin role");

        return tokenResponse;
    }

    public AuthenticationResponse refreshToken(String email) {
        return authenticationService.refreshToken(email);
    }
}

